import java.util.*;

public class JvmMemoryAnalyzer {

    public record HeapSnapshot(long timestampMs, long usedMb, long totalMb, boolean afterGc) {}

    private final List<HeapSnapshot> snapshots = new ArrayList<>();

    public void recordSnapshot(long timestampMs, long usedMb, long totalMb, boolean afterGc) {
        snapshots.add(new HeapSnapshot(timestampMs, usedMb, totalMb, afterGc));
    }

    public double averageUsagePercent() {
        // Return average of (usedMb/totalMb*100) across all snapshots
        if (snapshots.isEmpty()) return 0.0;
        return snapshots.stream()
            .mapToDouble(s -> (double) s.usedMb() / s.totalMb() * 100)
            .average()
            .orElse(0.0);
    }

    public boolean isPotentialMemoryLeak() {
        // Return true if the last 3 non-GC snapshots show strictly increasing usedMb
        return false; // TODO
    }

    public double gcEfficiency() {
        // For each pair of (pre-GC, post-GC) consecutive snapshots,
        // compute freedMb = preGC.usedMb - postGC.usedMb
        // Return average freed percentage relative to pre-GC usedMb
        return 0.0; // TODO
    }

    public static void main(String[] args) {
        JvmMemoryAnalyzer analyzer = new JvmMemoryAnalyzer();
        analyzer.recordSnapshot(0,    200, 512, false);
        analyzer.recordSnapshot(1000, 380, 512, false);
        analyzer.recordSnapshot(1100, 120, 512, true);  // after GC
        analyzer.recordSnapshot(2000, 250, 512, false);
        analyzer.recordSnapshot(3000, 310, 512, false);
        analyzer.recordSnapshot(4000, 370, 512, false);

        System.out.printf("Avg usage: %.1f%%%n", analyzer.averageUsagePercent());
        System.out.println("Leak detected: " + analyzer.isPotentialMemoryLeak());
        System.out.printf("GC efficiency: %.1f%%%n", analyzer.gcEfficiency());
    }
}

