import java.util.*;

public class LruCache<K, V> {

    private final int capacity;
    private final LinkedHashMap<K, V> cache;
    private int hits = 0;
    private int misses = 0;

    public LruCache(int capacity) {
        this.capacity = capacity;
        // LinkedHashMap with access order (true) evicts LRU on removeEldestEntry
        this.cache = new LinkedHashMap<>(capacity, 0.75f, true) {
            @Override
            protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {
                return size() > LruCache.this.capacity;
            }
        };
    }

    public void put(K key, V value) {
        cache.put(key, value);
    }

    public V get(K key) {
        V value = cache.get(key);
        if (value != null) hits++;
        else misses++;
        return value;
    }

    public double hitRate() {
        int total = hits + misses;
        return total == 0 ? 0.0 : (double) hits / total * 100;
    }

    public int size() { return cache.size(); }

    public boolean containsKey(K key) {
        // Check without affecting LRU order or hit/miss counts
        return cache.containsKey(key);
    }

    public static void main(String[] args) {
        LruCache<String, Integer> cache = new LruCache<>(3);
        cache.put("a", 1);
        cache.put("b", 2);
        cache.put("c", 3);

        cache.get("a"); // hit
        cache.get("a"); // hit
        cache.get("d"); // miss

        cache.put("e", 5); // evicts LRU (b, since a was accessed last and c is more recent than b)

        System.out.printf("Hit rate: %.1f%%%n", cache.hitRate());
        System.out.println("Contains b: " + cache.containsKey("b"));
        System.out.println("Contains a: " + cache.containsKey("a"));
        System.out.println("Size: " + cache.size());
    }
}
